32→      if (e.button !== 0) return;
33→
34→      const floor = getFloor(activeFloorId);
35→      if (!floor) return;
36→
37→      const column = findColumnAtPoint(floor.columns || [], modelPos);
38→      if (!column) {
39→        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Click a column to place a beam.' });
40→        return;
41→      }
42→
43→      if (!toolState.startColumnId) {
44→        editorDispatch({
45→          type: 'UPDATE_TOOL_STATE',
46→          payload: {
47→            startColumnId: column.id,
48→            previewColumnId: column.id,
49→          },
50→        });
51→        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Select the end column for the beam.' });
52→        return;
53→      }
54→
55→      if (toolState.startColumnId === column.id) {
56→        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Choose a different end column.' });
57→        return;
58→      }
59→
60→      const beam = createBeam(
61→        { kind: 'column', id: toolState.startColumnId },
62→        { kind: 'column', id: column.id },
63→        BEAM_WIDTH,
64→        BEAM_DEPTH,
65→        getFloorElevation(floor)
66→      );
67→
68→      dispatch({ type: 'BEAM_ADD', floorId: activeFloorId, beam });
69→      editorDispatch({ type: 'SELECT_OBJECT', id: beam.id, objectType: 'beam' });
70→      editorDispatch({
71→        type: 'UPDATE_TOOL_STATE',
72→        payload: {
73→          startColumnId: null,
74→          previewColumnId: null,
75→        },
76→      });
77→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Beam created.' });
78→    },
79→
80→    onKeyDown(e) {
81→      if (e.key === 'Escape') {
82→        editorDispatch({
83→          type: 'UPDATE_TOOL_STATE',
84→          payload: {
85→            startColumnId: null,
86→            previewColumnId: null,
87→          },
88→        });
89→        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
90→      }
91→    },
92→
93→    getCursor(toolState) {
94→      return toolState.startColumnId ? 'copy' : 'crosshair';
95→    },
96→  };
97→}
