 1→import { createLanding } from '@/domain/models';
 2→import { GRID_MINOR } from '@/domain/defaults';
 3→
 4→function snapToGrid(value) {
 5→  return Math.round(value / GRID_MINOR) * GRID_MINOR;
 6→}
 7→
 8→export function createLandingPlaceHandler({ dispatch, editorDispatch, activeFloorId, snapEnabled }) {
 9→  return {
10→    onMouseMove(modelPos) {
11→      let x = modelPos.x;
12→      let y = modelPos.y;
13→      if (snapEnabled) {
14→        x = snapToGrid(x);
15→        y = snapToGrid(y);
16→      }
17→      editorDispatch({
18→        type: 'UPDATE_TOOL_STATE',
19→        payload: { previewX: x, previewY: y },
20→      });
21→    },
22→
23→    onMouseDown(modelPos, e) {
24→      if (e.button !== 0) return;
25→      let x = modelPos.x;
26→      let y = modelPos.y;
27→      if (snapEnabled) {
28→        x = snapToGrid(x);
29→        y = snapToGrid(y);
30→      }
31→      const landing = createLanding({ x, y });
32→      dispatch({ type: 'LANDING_ADD', floorId: activeFloorId, landing });
33→      editorDispatch({ type: 'SELECT_OBJECT', id: landing.id, objectType: 'landing' });
34→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Landing placed.' });
35→    },
36→
37→    onKeyDown(e) {
38→      if (e.key === 'Escape') {
39→        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
40→      }
41→    },
42→
43→    getCursor() {
44→      return 'crosshair';
45→    },
46→  };
47→}
