 1→import { LANDING_WIDTH, LANDING_DEPTH } from '@/domain/defaults';
 2→import { TOOLS } from '@/editor/tools';
 3→import { landingOutline } from '@/geometry/landingGeometry';
 4→
 5→export default function LandingPreview({ toolState, activeTool }) {
 6→  if (activeTool !== TOOLS.LANDING) return null;
 7→  if (toolState.previewX == null || toolState.previewY == null) return null;
 8→
 9→  const previewLanding = {
10→    position: { x: toolState.previewX, y: toolState.previewY },
11→    width: LANDING_WIDTH,
12→    depth: LANDING_DEPTH,
13→    rotation: 0,
14→  };
15→
16→  const outline = landingOutline(previewLanding);
17→  if (outline.length < 3) return null;
18→
19→  const points = outline.map((p) => `${p.x},${p.y}`).join(' ');
20→
21→  return (
22→    <g style={{ pointerEvents: 'none' }}>
23→      <polygon
24→        points={points}
25→        fill="rgba(160, 165, 175, 0.12)"
26→        stroke="var(--color-selection)"
27→        strokeWidth={2}
28→        strokeDasharray="6 3"
29→        vectorEffect="non-scaling-stroke"
30→      />
31→    </g>
