 1→import { TOOLS } from '@/editor/tools';
 2→import { BEAM_WIDTH, BEAM_DEPTH } from '@/domain/defaults';
 3→import { getBeamRenderData } from '@/geometry/beamGeometry';
 4→
 5→export default function BeamPreview({ toolState, activeTool, columns, floorLevel }) {
 6→  if (activeTool !== TOOLS.BEAM) return null;
 7→  if (!toolState.startColumnId || !toolState.previewColumnId || toolState.startColumnId === toolState.previewColumnId) {
 8→    return null;
 9→  }
10→
11→  const previewBeam = {
12→    id: 'beam_preview',
13→    startRef: { kind: 'column', id: toolState.startColumnId },
14→    endRef: { kind: 'column', id: toolState.previewColumnId },
15→    width: BEAM_WIDTH,
16→    depth: BEAM_DEPTH,
17→    floorLevel: floorLevel ?? 0,
18→  };
19→
20→  const renderData = getBeamRenderData(previewBeam, columns || []);
21→  if (!renderData) return null;
22→
23→  const points = renderData.outline.map((point) => `${point.x},${point.y}`).join(' ');
24→
25→  return (
26→    <polygon
27→      points={points}
28→      fill="rgba(143, 170, 194, 0.25)"
29→      stroke="var(--color-selection)"
30→      strokeWidth={2}
31→      strokeDasharray="6 3"
32→      vectorEffect="non-scaling-stroke"
33→      style={{ pointerEvents: 'none' }}
34→    />
35→  );
36→}
